                last,
                workersStart,
                workersEnd,
                sameWorkers,
                beforeClose,
                daemon.isBalanced(),
                loadedBefore,
                CLASS_LOADING.getLoadedClassCount(),
                unloadedBefore,
                CLASS_LOADING.getUnloadedClassCount()
